import React, { useState, useEffect } from 'react';
import { gameStateService } from '../../../src/services/GameStateService';
import { eventBus, Events } from '../../../src/core/EventBus';

/**
 * Hook para subscrever ao modo de jogo ECS.
 */
export function useGameMode() {
    const [mode, setMode] = useState(gameStateService.getMode());
    
    useEffect(() => {
        const unsub = gameStateService.subscribe(() => {
            setMode(gameStateService.getMode());
        });
        return unsub;
    }, []);

    return mode;
}
